<?php
namespace App\Modules\Hr\Lifecycle\Actions;use App\Modules\Hr\Asset\Enums\AssetAssignmentStatus;use App\Modules\Hr\Asset\Models\HrAssetAssignment;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Lifecycle\Models\HrOffboardingChecklist;use App\Modules\Hr\Lifecycle\Models\HrOffboardingTask;use App\Modules\Hr\Personnel\Enums\EmployeeStatus;use App\Modules\Hr\Personnel\Models\HrEmployee;use Illuminate\Support\Facades\DB;
class ManageOffboardingAction{public function __construct(private HrAuditService $audit){}public function start(HrEmployee $employee,string $lastDay,string $reason):HrOffboardingChecklist{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.lifecycle.manage'),403);abort_unless($employee->legal_entity_id===$tenant&&$employee->status===EmployeeStatus::Active,422);abort_if(blank($reason),422);return DB::transaction(function()use($employee,$lastDay,$reason,$tenant){$checklist=HrOffboardingChecklist::firstOrCreate(['employee_id'=>$employee->id,'status'=>'active'],['legal_entity_id'=>$tenant,'last_working_on'=>$lastDay,'termination_reason'=>trim($reason),'created_by'=>auth()->id()]);foreach([['assets','Tüm zimmetleri iade al'],['access','Sistem erişimlerini kapat'],['documents','Çıkış belgelerini tamamla'],['exit_interview','Çıkış görüşmesini kaydet']] as [$key,$title])HrOffboardingTask::firstOrCreate(['checklist_id'=>$checklist->id,'template_key'=>$key],['legal_entity_id'=>$tenant,'title'=>$title,'due_on'=>$lastDay,'is_required'=>true,'status'=>'pending']);$this->audit->log('offboarding_started',$checklist);return $checklist;});}public function close(HrOffboardingChecklist $checklist):HrOffboardingChecklist{abort_unless(auth()->user()?->hasHrPermission('hr.lifecycle.manage'),403);$tenant=app(TenantContext::class)->getId();abort_unless($checklist->legal_entity_id===$tenant&&$checklist->status==='active',422);abort_if($checklist->tasks()->where('is_required',true)->where('status','!=','completed')->exists(),422,'Zorunlu çıkış görevleri tamamlanmadı.');abort_if(HrAssetAssignment::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('employee_id',$checklist->employee_id)->where('status',AssetAssignmentStatus::Assigned->value)->exists(),422,'Açık zimmetler iade edilmeden çıkış kapatılamaz.');return DB::transaction(function()use($checklist){$employee=$checklist->employee;$employee->activeEmployment?->update(['status'=>'terminated','end_date'=>$checklist->last_working_on,'termination_reason'=>$checklist->termination_reason,'updated_by'=>auth()->id()]);$employee->update(['status'=>EmployeeStatus::Terminated,'updated_by'=>auth()->id()]);$checklist->update(['status'=>'completed','completed_at'=>now()]);$this->audit->log('offboarding_completed',$checklist);return $checklist->fresh();});}}
